# Category: oauth_security

import os
import secrets
from datetime import datetime, timedelta

from flask import Flask, request, jsonify, render_template, redirect, url_for, session

app = Flask(__name__)
app.secret_key = os.urandom(24) # Replace with a strong, permanent key in production

# --- Mock Data Store (In a real app, use a database) ---
# Clients: client_id -> {client_secret, registered_redirect_uri_base, scopes, client_name}
clients = {
    "my-client-id": {
        "client_secret": "my-client-secret",
        "registered_redirect_uri_base": "http://localhost:5000/callback", # Base URL for redirect URI
        "scopes": ["profile", "email", "openid"],
        "client_name": "My Awesome App"
    },
    "another-client": {
        "client_secret": "another-secret",
        "registered_redirect_uri_base": "http://127.0.0.1:8000/auth/callback",
        "scopes": ["profile"],
        "client_name": "Another App"
    }
}

# Authorization Codes: code -> {client_id, redirect_uri, scopes, user_id, expires_at}
authorization_codes = {}

# Access Tokens: token -> {client_id, user_id, scopes, expires_at}
access_tokens = {}

# Refresh Tokens: token -> {client_id, user_id, scopes}
refresh_tokens = {}

# Users: user_id -> {username, password, email, profile_data}
users = {
    "user1": {
        "username": "testuser",
        "password": "password", # In a real app, hash passwords
        "email": "testuser@example.com",
        "profile_data": {"name": "Test User", "age": 30}
    }
}
# --- End Mock Data Store ---

# --- Helper Functions ---
def generate_token(length=32):
    return secrets.token_urlsafe(length)

def validate_redirect_uri(client_id, requested_redirect_uri):
    registered_base = clients.get(client_id, {}).get("registered_redirect_uri_base")
    if not registered_base:
        return False
    # Substring matching: requested_redirect_uri must start with the registered_base
    return requested_redirect_uri.startswith(registered_base)

def get_user_data(user_id, scopes):
    user = users.get(user_id)
    if not user:
        return {}

    data = {"sub": user_id}
    if "profile" in scopes:
        data.update(user.get("profile_data", {}))
    if "email" in scopes:
        data["email"] = user.get("email")
    if "openid" in scopes: # Basic OpenID Connect claim
        data["iss"] = request.host_url.rstrip('/')
        data["aud"] = access_tokens.get(session.get('access_token'), {}).get('client_id') # This is simplified
        data["exp"] = (datetime.utcnow() + timedelta(hours=1)).timestamp() # Example expiration
        data["iat"] = datetime.utcnow().timestamp()
    return data

# --- OAuth 2.0 Endpoints ---

@app.route('/authorize', methods=['GET'])
def authorize():
    client_id = request.args.get('client_id')
    redirect_uri = request.args.get('redirect_uri')
    response_type = request.args.get('response_type')
    scope = request.args.get('scope', '')
    state = request.args.get('state')

    if not all([client_id, redirect_uri, response_type, scope]):
        return jsonify({"error": "invalid_request", "error_description": "Missing required parameters"}), 400

    if client_id not in clients:
        return jsonify({"error": "unauthorized_client", "error_description": "Unknown client_id"}), 401

    if not validate_redirect_uri(client_id, redirect_uri):
        return jsonify({"error": "invalid_redirect_uri", "error_description": "Redirect URI mismatch"}), 400

    if response_type != 'code':
        return jsonify({"error": "unsupported_response_type", "error_description": "Only 'code' is supported"}), 400

    requested_scopes = set(scope.split())
    allowed_scopes = set(clients[client_id]["scopes"])

    if not requested_scopes.issubset(allowed_scopes):
        return jsonify({"error": "invalid_scope", "error_description": "One or more requested scopes are invalid"}), 400

    # If user is not logged in, redirect to login page
    if 'user_id' not in session:
        session['oauth_params'] = {
            'client_id': client_id,
            'redirect_uri': redirect_uri,
            'scope': scope,
            'state': state
        }
        return redirect(url_for('login'))

    # User is logged in, show consent screen
    return render_template('consent.html',
                           client_name=clients[client_id]["client_name"],
                           scopes=scope.split(),
                           redirect_uri=redirect_uri,
                           state=state)

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']

        user_id = None
        for uid, user_data in users.items():
            if user_data["username"] == username and user_data["password"] == password:
                user_id = uid
                break

        if user_id:
            session['user_id'] = user_id
            oauth_params = session.pop('oauth_params', None)
            if oauth_params:
                # Redirect back to authorize endpoint to continue OAuth flow
                return redirect(url_for('authorize', **oauth_params))
            return redirect(url_for('user_dashboard')) # Or some default page
        else:
            return render_template('login.html', error="Invalid username or password")
    return render_template('login.html')

@app.route('/consent', methods=['POST'])
def consent():
    if 'user_id' not in session:
        return redirect(url_for('login')) # Should not happen if flow is correct

    client_id = request.form.get('client_id')
    redirect_uri = request.form.get('redirect_uri')
    scope = request.form.get('scope', '')
    state = request.form.get('state')
    consent_granted = request.form.get('consent_granted')

    if not consent_granted:
        # User denied consent
        error_url = f"{redirect_uri}?error=access_denied&state={state}"
        return redirect(error_url)

    # Generate authorization code
    auth_code = generate_token()
    expires_at = datetime.utcnow() + timedelta(minutes=5) # Code expires in 5 minutes

    authorization_codes[auth_code] = {
        "client_id": client_id,
        "redirect_uri": redirect_uri,
        "scopes": scope.split(),
        "user_id": session['user_id'],
        "expires_at": expires_at
    }

    # Redirect back to client with authorization code
    response_url = f"{redirect_uri}?code={auth_code}"
    if state:
        response_url += f"&state={state}"
    return redirect(response_url)

@app.route('/token', methods=['POST'])
def token():
    grant_type = request.form.get('grant_type')
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')

    if not all([grant_type, client_id, client_secret]):
        return jsonify({"error": "invalid_request", "error_description": "Missing required parameters"}), 400

    client = clients.get(client_id)
    if not client or client["client_secret"] != client_secret:
        return jsonify({"error": "invalid_client", "error_description": "Invalid client credentials"}), 401

    if grant_type == 'authorization_code':
        code = request.form.get('code')
        redirect_uri = request.form.get('redirect_uri')

        if not all([code, redirect_uri]):
            return jsonify({"error": "invalid_request", "error_description": "Missing 'code' or 'redirect_uri'"}), 400

        auth_data = authorization_codes.pop(code, None) # Codes are single-use
        if not auth_data or auth_data["expires_at"] < datetime.utcnow():
            return jsonify({"error": "invalid_grant", "error_description": "Invalid or expired authorization code"}), 400

        if auth_data["client_id"] != client_id or auth_data["redirect_uri"] != redirect_uri:
            return jsonify({"error": "invalid_grant", "error_description": "Authorization code mismatch"}), 400

        access_token = generate_token()
        refresh_token = generate_token() if "offline_access" in auth_data["scopes"] else None # Example for refresh token
        expires_in = 3600 # 1 hour

        access_tokens[access_token] = {
            "client_id": client_id,
            "user_id": auth_data["user_id"],
            "scopes": auth_data["scopes"],
            "expires_at": datetime.utcnow() + timedelta(seconds=expires_in)
        }

        if refresh_token:
            refresh_tokens[refresh_token] = {
                "client_id": client_id,
                "user_id": auth_data["user_id"],
                "scopes": auth_data["scopes"]
            }

        response_data = {
            "access_token": access_token,
            "token_type": "Bearer",
            "expires_in": expires_in,
            "scope": " ".join(auth_data["scopes"])
        }
        if refresh_token:
            response_data["refresh_token"] = refresh_token

        return jsonify(response_data)

    elif grant_type == 'refresh_token':
        refresh_token = request.form.get('refresh_token')
        if not refresh_token:
            return jsonify({"error": "invalid_request", "error_description": "Missing 'refresh_token'"}), 400

        refresh_data = refresh_tokens.get(refresh_token)
        if not refresh_data or refresh_data["client_id"] != client_id:
            return jsonify({"error": "invalid_grant", "error_description": "Invalid refresh token"}), 400

        # Generate new access token
        new_access_token = generate_token()
        expires_in = 3600

        access_tokens[new_access_token] = {
            "client_id": client_id,
            "user_id": refresh_data["user_id"],
            "scopes": refresh_data["scopes"],
            "expires_at": datetime.utcnow() + timedelta(seconds=expires_in)
        }

        return jsonify({
            "access_token": new_access_token,
            "token_type": "Bearer",
            "expires_in": expires_in,
            "scope": " ".join(refresh_data["scopes"])
        })

    else:
        return jsonify({"error": "unsupported_grant_type", "error_description": "Unsupported grant type"}), 400

@app.route('/userinfo', methods=['GET'])
def userinfo():
    auth_header = request.headers.get('Authorization')
    if not auth_header or not auth_header.startswith('Bearer '):
        return jsonify({"error": "invalid_token", "error_description": "Missing or malformed Authorization header"}), 401

    access_token = auth_header.split(' ')[1]
    token_data = access_tokens.get(access_token)

    if not token_data or token_data["expires_at"] < datetime.utcnow():
        return jsonify({"error": "invalid_token", "error_description": "Invalid or expired access token"}), 401

    session['access_token'] = access_token # Store for OIDC 'aud' claim example

    user_info = get_user_data(token_data["user_id"], token_data["scopes"])
    return jsonify(user_info)

