@app.route('/')
def index():
    return "<h1>OAuth 2.0 Authorization Server</h1><p>Visit <a href='/login'>login</a> to start.</p>"

@app.route('/user_dashboard')
def user_dashboard():
    if 'user_id' not in session:
        return redirect(url_for('login'))
    user = users.get(session['user_id'])
    return f"<h1>Welcome, {user['username']}!</h1><p>You are logged in.</p><p><a href='/logout'>Logout</a></p>"

@app.route('/logout')
def logout():
    session.pop('user_id', None)
    return redirect(url_for('index'))

